def run_benchmark():
    print("🏛️ Kenbun Strategy Benchmark v1.2")
    print("========================================")
    
    # Use the imported router instance
    passed = 0
    failures = []
    
    print(f"Running benchmark on {len(test_cases)} cases...")

    for i, case in enumerate(test_cases):
        task = case["task"]
        expected = case["expected_path"]
        
        path = router.get_strategy_path(task)
        
        if path == expected:
            passed += 1
            if (i + 1) % 1000 == 0:
                print(f"Progress: {i+1}/{len(test_cases)}...")
        else:
            failures.append({
                "name": case["name"],
                "task": task,
                "expected": expected,
                "actual": path
            })

    print("\n" + "="*40)
    print(f"📊 FINAL SCORE: {passed}/{len(test_cases)} ({passed/len(test_cases)*100:.1f}%)")
    print("="*40)
    
    if failures:
        print(f"❌ FAILURES DETECTED: {len(failures)}")
        print("Sample Failure:")
        f = failures[0]
        print(f"- {f['name']}: {f['task'][:70]}... \n  (Expected: {f['expected']}, Got: {f['actual']})")

    # Count actual records on disk
    log_count = 0
    if ROUTING_LOG.exists():
        with open(ROUTING_LOG, "r") as f:
            log_count = sum(1 for _ in f)
            
    print(f"💾 DATA COLLECTION: {log_count} records saved to {ROUTING_LOG.name}")

if __name__ == "__main__":
    run_benchmark()
